"""matplotlib.ticker — tick locating and formatting."""

import numpy as _np


class Locator:
    """Base tick locator."""
    MAXTICKS = 1000

    def __call__(self):
        return self.tick_values(None, None)

    def tick_values(self, vmin, vmax):
        return []

    def set_params(self, **kwargs):
        for k, v in kwargs.items():
            setattr(self, k, v)

    def view_limits(self, vmin, vmax):
        return (vmin, vmax)


class MaxNLocator(Locator):
    def __init__(self, nbins='auto', *, steps=None, integer=False,
                 symmetric=False, prune=None, min_n_ticks=2):
        self.nbins = nbins if nbins != 'auto' else 10
        self.steps = steps
        self.integer = integer
        self.symmetric = symmetric
        self.prune = prune
        self.min_n_ticks = min_n_ticks

    def tick_values(self, vmin, vmax):
        if vmin is None or vmax is None:
            return []
        return _np.linspace(vmin, vmax, self.nbins + 1).tolist()


class MultipleLocator(Locator):
    def __init__(self, base=1.0, offset=0.0):
        self.base = base
        self.offset = offset

    def tick_values(self, vmin, vmax):
        if vmin is None or vmax is None:
            return []
        lo = _np.ceil((vmin - self.offset) / self.base) * self.base + self.offset
        hi = _np.floor((vmax - self.offset) / self.base) * self.base + self.offset
        return _np.arange(lo, hi + self.base * 0.5, self.base).tolist()


class FixedLocator(Locator):
    def __init__(self, locs, nbins=None):
        self.locs = list(locs)
        self.nbins = nbins

    def tick_values(self, vmin, vmax):
        return self.locs


class IndexLocator(Locator):
    def __init__(self, base, offset):
        self.base = base
        self.offset = offset


class LinearLocator(Locator):
    def __init__(self, numticks=None, presets=None):
        self.numticks = numticks or 11

    def tick_values(self, vmin, vmax):
        if vmin is None or vmax is None:
            return []
        return _np.linspace(vmin, vmax, self.numticks).tolist()


class LogLocator(Locator):
    def __init__(self, base=10.0, subs=(1.0,), numdecs=4, numticks=None):
        self.base = base
        self.subs = subs
        self.numdecs = numdecs
        self.numticks = numticks


class SymmetricalLogLocator(Locator):
    def __init__(self, transform=None, subs=None, linthresh=None, base=None):
        self.transform = transform
        self.subs = subs
        self.linthresh = linthresh
        self.base = base


class AutoLocator(MaxNLocator):
    def __init__(self):
        super().__init__(nbins='auto', steps=[1, 2, 2.5, 5, 10])


class AutoMinorLocator(Locator):
    def __init__(self, n=None):
        self.ndivs = n


class NullLocator(Locator):
    def tick_values(self, vmin, vmax):
        return []


# ── Formatters ──────────────────────────────────────────────────

class Formatter:
    """Base tick formatter."""
    locs = []

    def __call__(self, x, pos=None):
        return self.format_data(x)

    def format_data(self, value):
        return str(value)

    def format_data_short(self, value):
        return self.format_data(value)

    def set_locs(self, locs):
        self.locs = locs

    def fix_minus(self, s):
        return s


class FuncFormatter(Formatter):
    def __init__(self, func):
        self.func = func

    def __call__(self, x, pos=None):
        return self.func(x, pos)


class FormatStrFormatter(Formatter):
    def __init__(self, fmt):
        self.fmt = fmt

    def __call__(self, x, pos=None):
        return self.fmt % x


class StrMethodFormatter(Formatter):
    def __init__(self, fmt):
        self.fmt = fmt

    def __call__(self, x, pos=None):
        return self.fmt.format(x=x, pos=pos)


class ScalarFormatter(Formatter):
    def __init__(self, useOffset=None, useMathText=None, useLocale=None):
        self.useOffset = useOffset
        self.useMathText = useMathText
        self.useLocale = useLocale
        self.orderOfMagnitude = 0
        self.format = ''
        self.offset = 0

    def __call__(self, x, pos=None):
        return f'{x:g}'

    def set_scientific(self, b):
        pass

    def set_powerlimits(self, lims):
        pass

    def set_useOffset(self, val):
        self.useOffset = val


class LogFormatter(Formatter):
    def __init__(self, base=10.0, labelOnlyBase=False):
        self.base = base
        self.labelOnlyBase = labelOnlyBase

    def __call__(self, x, pos=None):
        if x <= 0:
            return ''
        return f'{x:g}'


class LogFormatterExponent(LogFormatter):
    pass


class LogFormatterMathtext(LogFormatter):
    pass


class LogFormatterSciNotation(LogFormatter):
    pass


class PercentFormatter(Formatter):
    def __init__(self, xmax=100, decimals=None, symbol='%', is_latex=False):
        self.xmax = xmax
        self.decimals = decimals
        self.symbol = symbol

    def __call__(self, x, pos=None):
        pct = x / self.xmax * 100
        if self.decimals is not None:
            return f'{pct:.{self.decimals}f}{self.symbol}'
        return f'{pct:g}{self.symbol}'


class EngFormatter(Formatter):
    def __init__(self, unit='', places=None, sep=' ', usetex=None, useMathText=None):
        self.unit = unit
        self.places = places
        self.sep = sep

    def __call__(self, x, pos=None):
        return f'{x:g}{self.sep}{self.unit}'


class NullFormatter(Formatter):
    def __call__(self, x, pos=None):
        return ''


class FixedFormatter(Formatter):
    def __init__(self, seq):
        self.seq = list(seq)
        self.offset_string = ''

    def __call__(self, x, pos=None):
        if pos is not None and pos < len(self.seq):
            return self.seq[pos]
        return ''


class DateFormatter(Formatter):
    def __init__(self, fmt, tz=None, *, usetex=None):
        self.fmt = fmt

    def __call__(self, x, pos=None):
        return str(x)
